head.b:template-skin:
body#layout{padding:20px;margin:0;background:#eef0f4;font-family:Arial,sans-serif;font-size:12px}
body#layout .site-header{position:static!important;box-shadow:none!important;border-bottom:3px solid #2563EB;background:#fff;margin-bottom:8px}
body#layout .site-header-inner{height:auto;padding:8px 16px}
body#layout .search-overlay,.skip-link,#btt,#read-progress{display:none!important}
body#layout .main-wrap{max-width:100%;padding:0}
body#layout .main-layout{display:block;overflow:hidden}
body#layout #post-wrapper{float:left;width:67%;min-height:200px;padding-right:8px}
body#layout #sidebar-wrapper{float:right;width:30%;min-height:100px}
body#layout #sidebar-wrapper .about-row{padding:4px}
body#layout .site-footer{clear:both;margin-top:8px;padding:8px 16px}
body#layout .footer-grid{display:block}
body#layout .footer-grid>div{padding:4px 0;margin-bottom:4px}
body#layout div.section>h4{background:#2563EB;color:#fff;padding:3px 10px;font-size:11px;margin:0 0 6px;text-align:center;display:block}
body#layout #custom-css h4{display:none}
body#layout #custom-css div.widget .widget-content{padding:6px 12px;background:#e4ffff}
body#layout #iklan-atas h4,
body#layout #iklan-tengah1 h4,
body#layout #iklan-tengah2 h4,
body#layout #iklan-bawah h4,
body#layout #matched-content h4{display:none}
body#layout #iklan-atas .widget-content,
body#layout #iklan-tengah1 .widget-content,
body#layout #iklan-tengah2 .widget-content,
body#layout #iklan-bawah .widget-content{background:#eaffe9;padding:6px 12px}
body#layout #matched-content .widget-content{background:#ffe9e9;padding:6px 12px}
body#layout #iklan-infeed .widget-content{background:#fff9e9;padding:6px 12px}
body#layout #custom-javascript-footer h4{display:none}
body#layout #custom-javascript-footer div.widget .widget-content{padding:6px 12px;background:#fff5e4}
body#layout #iklan-infeed h4{display:none}
body#layout #navmenu h4{display:none}
body#layout #navmenu div.widget .widget-content{padding:4px 8px;background:#fff3cd}
body#layout #navmenu-mobile h4{display:none}
body#layout #navmenu-mobile div.widget .widget-content{padding:4px 8px;background:#e8f4fd}
body#layout #footer-navmenu h4{display:none}
body#layout #footer-navmenu .widget-content{padding:4px 0}
body#layout #iklan-atas,
body#layout #iklan-tengah1,
body#layout #iklan-tengah2,
body#layout #iklan-bawah,
body#layout #matched-content,
body#layout #iklan-infeed{display:block}
body#layout .navmenu,
body#layout .navmenu-mobile,
body#layout .footer-navmenu{display:block}

body.script:
//
// Clean ?m=1 / ?m=0 from URL
(function(){
  var s = window.location.search;
  if(s.indexOf('m=1') > -1 || s.indexOf('m=0') > -1){
    var clean = window.location.href
      .replace(/[?&]m=[01]/g, '')
      .replace(/\?$/, '');
    window.history.replaceState(null, '', clean);
  }
})();

// Copyright year
document.getElementById('yr').textContent = new Date().getFullYear();

// Credit guard — example implementation for MIT-licensed templates.
// Users may customize or replace this with their own attribution check.
// Uncomment to enable redirect if the .spare-link credit is removed.
