// Header scroll shadow + back-to-top + reading progress
(function(){
  var h = document.querySelector('.site-header');
  var btt = document.getElementById('btt');
  var bar = document.getElementById('read-progress');
  window.addEventListener('scroll', function(){
    var y = window.scrollY;
    if(h) h.classList.toggle('scrolled', y > 10);
    if(btt) btt.classList.toggle('show', y > 300);
    if(bar && document.querySelector('.post-single')){
      bar.style.display = 'block';
      var total = Math.max(document.body.scrollHeight, document.documentElement.scrollHeight) - window.innerHeight;
      bar.style.width = (total > 0 ? (y / total * 100) : 0) + '%';
    }
  }, {passive:true});
})();

// Estimated reading time
(function(){
  var postBody = document.querySelector('.post-body');
  var meta = document.querySelector('.post-meta');
  if(!postBody || !meta) return;
  var words = postBody.textContent.trim().split(/\s+/).length;
  var mins = Math.max(1, Math.round(words / 200));
  var span = document.createElement('span');
  span.innerHTML = '<i class="ri-time-line"></i> ~' + mins + ' menit baca';
  meta.appendChild(span);
})();

// Clipboard helper with execCommand fallback
function copyText(text) {
  if (navigator.clipboard && navigator.clipboard.writeText) {
    return navigator.clipboard.writeText(text);
  }
  var ta = document.createElement('textarea');
  ta.value = text; ta.style.cssText = 'position:fixed;opacity:0;top:0;left:0';
  document.body.appendChild(ta); ta.focus(); ta.select();
  try { document.execCommand('copy'); } catch(e) {}
  document.body.removeChild(ta);
  return Promise.resolve();
}

// Copy link button
(function(){
  var btn = document.getElementById('copy-link-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    copyText(window.location.href).then(function(){
      btn.innerHTML = '<i class="ri-check-line"></i> Tersalin!';
      setTimeout(function(){ btn.innerHTML = '<i class="ri-link"></i> Salin Link'; }, 1500);
    });
  });
})();

// Code block copy button
// Guard: skip if copy-code-js.html component is already loaded (detects its data-cc-bound marker).
(function(){
  if(document.querySelector('[data-cc-bound]')) return;
  document.querySelectorAll('.post-body pre').forEach(function(pre){
    if(pre.dataset.ccBound) return;
    pre.dataset.ccBound = '1';
    var btn = document.createElement('button');
    btn.className = 'code-copy';
    btn.innerHTML = '<i class="ri-file-copy-line"></i>';
    btn.title = 'Salin kode';
    btn.addEventListener('click', function(){
      copyText(pre.textContent).then(function(){
        btn.innerHTML = '<i class="ri-check-line"></i>';
        setTimeout(function(){ btn.innerHTML = '<i class="ri-file-copy-line"></i>'; }, 1500);
      });
    });
    pre.style.position = 'relative';
    pre.appendChild(btn);
  });
})();

// External link handler (auto rel + target for post body links)
(function(){
  var postBody = document.querySelector('.post-body');
  if(!postBody) return;
  var host = window.location.hostname;
  postBody.querySelectorAll('a[href]').forEach(function(a){
    try {
      var url = new URL(a.href);
      if(url.hostname && url.hostname !== host){
        a.setAttribute('target', '_blank');
        a.setAttribute('rel', 'nofollow noopener noreferrer');
      }
    } catch(e){}
  });
})();

// HTML escape helper (XSS prevention for feed-injected content)
// Also exposed as window.__h.escHtml so components can share it without redefining.
function escHtml(s){
  return String(s||'').replace(/[&<>"']/g,function(c){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});
}
(window.__h = window.__h || {}).escHtml = escHtml;

// Related posts via Blogger Feeds API (same label as current post)
// Guard: skip if related-posts-js.html component is already loaded (it renders .related-section).
(function(){
  if(document.querySelector('.related-section')) return;
  var grid = document.getElementById('related-grid');
  if(!grid) return;
  var labels = document.querySelectorAll('.post-footer-labels .tag-label');
  if(!labels.length){ document.getElementById('related-posts').style.display='none'; return; }
  var label = labels[0].textContent.trim();
  var brand = document.querySelector('a.brand');
  var blogUrl = brand ? brand.href : (window.location.origin + '/');
  // Use canonical post URL from Blogger (not window.location which may have query/hash)
  var canonical = (document.querySelector('link[rel="canonical"]') || {}).href || window.location.href;
  function normalize(u){ try{ var x=new URL(u); return (x.hostname.toLowerCase()+x.pathname).replace(/\/+$/,''); }catch(e){ return String(u||'').split('?')[0].split('#')[0].replace(/\/+$/,''); } }
  var currentUrl = normalize(canonical);
  fetch(blogUrl+'feeds/posts/summary/-/'+encodeURIComponent(label)+'?alt=json&max-results=8')
    .then(function(r){return r.json();})
    .then(function(data){
      var entries = (data.feed.entry||[]).filter(function(e){
        var link = (e.link||[]).find(function(l){return l.rel==='alternate';});
        return link && normalize(link.href) !== currentUrl;
      }).slice(0,3);
      if(!entries.length){document.getElementById('related-posts').style.display='none';return;}
      grid.innerHTML = entries.map(function(e){
        var link = (e.link||[]).find(function(l){return l.rel==='alternate';});
        var href = link ? link.href : '#';
        var title = escHtml(e.title.$t);
        var thumb = e['media$thumbnail'] ? e['media$thumbnail'].url.replace(/\/s\d+[^/]*\//,'/s600-c/').replace(/=s\d+\S*$/,'=s600-c') : '';
        var date = e.published.$t ? new Date(e.published.$t).toLocaleDateString('id-ID',{day:'numeric',month:'short',year:'numeric'}) : '';
        return '<div class="rel-card"><a class="rel-thumb" href="'+href+'">'+(thumb?'<img src="'+thumb+'" alt="'+title+'" width="600" height="375" loading="lazy"/>':'<i class="ri-article-line"></i>')+'</a><div class="rel-body"><div class="rel-title"><a href="'+href+'">'+title+'</a></div><div class="rel-date">'+date+'</div></div></div>';
      }).join('');
    }).catch(function(){document.getElementById('related-posts').style.display='none';});
})();

// Jelajahi Kategori via Blogger Feeds API
(function(){
  var grid = document.getElementById('cat-explore-grid');
  if(!grid) return;
  var brand = document.querySelector('a.brand');
  var blogUrl = brand ? brand.href : (window.location.origin + '/');
  // max-results=0 returns feed metadata (all categories) without entries
  var url = blogUrl + 'feeds/posts/summary?alt=json&max-results=0';
  function render(data){
    var cats = (data && data.feed && data.feed.category) || [];
    if(!cats.length){ grid.parentElement.style.display='none'; return false; }
    grid.innerHTML = cats.map(function(c){
      var rawName = c.term;
      var name = escHtml(rawName);
      var href = blogUrl + 'search/label/' + encodeURIComponent(rawName);
      return '<a class="cat-explore-item" href="'+href+'"><span>'+name+'</span></a>';
    }).join('');
    return true;
  }
  fetch(url).then(function(r){return r.json();}).then(function(data){
    if(render(data)) return;
    // Fallback: some Blogger configs ignore max-results=0 — retry with high limit
    return fetch(blogUrl+'feeds/posts/summary?alt=json&max-results=1').then(function(r){return r.json();}).then(render);
  }).catch(function(){ grid.parentElement.style.display='none'; });
})();

// Ad slot inject — article positions
if(_bv.isPost){
!function(){
  var body = document.querySelector('.post-body');
  if(!body) return;
  var allParas = Array.from(body.querySelectorAll('p'));
  var paras = allParas.filter(function(p){
    return !p.closest('blockquote, table, pre, ul, ol, .ad-slot, figcaption');
  });
  var atas = document.querySelector('#iklan-atas .ad-slot');
  var tengah1 = document.querySelector('#iklan-tengah1 .ad-slot');
  var tengah2 = document.querySelector('#iklan-tengah2 .ad-slot');
  var bawah = document.querySelector('#iklan-bawah .ad-slot');
  var matched = document.querySelector('#matched-content .ad-slot');
  var p1 = Math.ceil(0.2 * paras.length);
  var p2 = Math.ceil(0.7 * paras.length);
  if(atas && atas.innerHTML.trim()){ body.insertBefore(atas, body.firstChild); atas.style.display=''; }
  if(bawah && bawah.innerHTML.trim()){ body.appendChild(bawah); bawah.style.display=''; }
  if(tengah1 && tengah1.innerHTML.trim() && paras[p1]){
    paras[p1].parentNode.insertBefore(tengah1, paras[p1].nextSibling); tengah1.style.display='';
  }
  if(tengah2 && tengah2.innerHTML.trim() && paras[p2]){
    paras[p2].parentNode.insertBefore(tengah2, paras[p2].nextSibling); tengah2.style.display='';
  }
  if(matched && matched.innerHTML.trim()){
    var related = document.getElementById('related-posts');
    if(related){ related.parentNode.insertBefore(matched, related.nextSibling); }
    else{ var ps = document.querySelector('.post-single'); if(ps) ps.appendChild(matched); }
    matched.style.display='';
  }
}();
}

// Ad slot inject — in-feed homepage
if(_bv.isHome){
!function(){
  var list = document.querySelector('.post-list');
  if(!list) return;
  var cards = list.querySelectorAll('article.post-card');
  var slot = document.querySelector('#iklan-infeed .ad-infeed');
  if(!slot || !slot.innerHTML.trim() || cards.length < 3) return;
  var wrapper = document.createElement('div');
  wrapper.className = 'ad-slot ad-infeed-wrap';
  wrapper.appendChild(slot);
  list.insertBefore(wrapper, cards[2].nextSibling);
}();
}

// Archive: group flat list by year (extract year from URL /YYYY/MM/)
// Defensive: works for both FLAT and HIERARCHY mode (b:includable already normalizes to month <li>s)
(function(){
  var ul = document.getElementById('archive-list');
  if(!ul) return;
  var items = Array.from(ul.querySelectorAll('li.arch-item'));
  if(!items.length) return;
  var groups = {}, order = [], hasYear = false;
  items.forEach(function(li){
    var a = li.querySelector('a');
    var href = a ? (a.getAttribute('href') || '') : '';
    var m = href.match(/\/(\d{4})\//);
    var yr = m ? m[1] : '\u2014';
    if(m) hasYear = true;
    if(!groups[yr]){ groups[yr] = []; order.push(yr); }
    groups[yr].push(li.cloneNode(true));
  });
  // Fallback: no year extractable from any item — keep flat list as-is
  if(!hasYear) return;
  ul.innerHTML = '';
  order.forEach(function(yr, idx){
    var details = document.createElement('details');
    details.className = 'archive-year-item';
    var summary = document.createElement('summary');
    summary.className = 'archive-year';
    var ySpan = document.createElement('span');
    ySpan.textContent = yr;
    var chevron = document.createElement('i');
    chevron.className = 'ri-arrow-down-s-line yr-chevron';
    summary.appendChild(ySpan);
    summary.appendChild(chevron);
    details.appendChild(summary);
    var mUl = document.createElement('ul');
    mUl.className = 'archive-months';
    groups[yr].forEach(function(mLi){ mUl.appendChild(mLi); });
    details.appendChild(mUl);
    ul.appendChild(details);
  });
})();

// Keyboard shortcut: "/" to open search overlay
(function(){
  document.addEventListener('keydown', function(e){
    if(e.key !== '/' || e.ctrlKey || e.metaKey || e.altKey) return;
    if(window.innerWidth <= 768) return;
    var tag = (e.target.tagName || '').toLowerCase();
    if(tag === 'input' || tag === 'textarea' || e.target.isContentEditable) return;
    var toggle = document.getElementById('search-toggle');
    if(!toggle) return;
    e.preventDefault();
    toggle.checked = true;
    setTimeout(function(){
      var input = document.getElementById('search-input-main');
      if(input) input.focus();
    }, 50);
  });
  // ESC to close
  document.addEventListener('keydown', function(e){
    if(e.key !== 'Escape') return;
    var toggle = document.getElementById('search-toggle');
    if(toggle && toggle.checked){ toggle.checked = false; }
  });
})();

// Archive accordion: animate close direction
(function(){
  document.addEventListener('click', function(e){
    var summary = e.target.closest('summary.archive-year');
    if(!summary) return;
    var details = summary.parentElement;
    if(!details || details.tagName !== 'DETAILS') return;
    // Only intercept when closing (currently open)
    if(!details.open) return;
    e.preventDefault();
    e.stopPropagation();
    var content = details.querySelector('.archive-months');
    if(!content){ details.removeAttribute('open'); return; }
    // Avoid double-trigger if already closing
    if(content.classList.contains('arch-closing')) return;
    content.classList.add('arch-closing');
    var closed = false;
    function finish(){
      if(closed) return;
      closed = true;
      content.classList.remove('arch-closing');
      details.removeAttribute('open');
      content.removeEventListener('animationend', onEnd);
    }
    function onEnd(ev){
      if(ev.animationName !== 'archClose') return;
      finish();
    }
    content.addEventListener('animationend', onEnd);
    // Fallback timeout in case animationend doesn't fire (reduced-motion, etc.)
    setTimeout(finish, 260);
  });
})();

//
